// Solution
var express = require('express');
var app = express();

// Middleware function to validate route parameter `id`
var validateId = function(req, res, next) {
  var id = parseInt(req.params.id);
  if (isNaN(id) || !validUserIds.includes(id)) {
    res.status(404).send('User not found');
  } else {
    next();
  }
}

// Predefined array of valid user IDs
var validUserIds = [1, 2, 3];

// Route definition
app.get('/users/:id', validateId, function(req, res) {
  res.send('User found');
});

app.listen(3000, function() {
  console.log('Server listening on port 3000');
});
